// Summary: Client MediaPlayer wiring native audio with MediaControl and Slider instances for seek and volume plus layout variants.

import * as React from 'react';
import { IconButton } from '../IconButton';
import { MediaControl } from '../MediaControl';
import { Slider } from '../Slider';
import {
  CloseIcon,
  Forward10Icon,
  Replay10Icon,
  VolumeDownIcon,
  VolumeOffIcon,
  VolumeUpIcon
} from '../../../icons';
import { formatTime, clamp, collapseWhitespace, composeClasses } from '../../../utilities';

type MediaPlayerVariant = 'default' | 'compact' | 'mini';

export interface MediaPlayerProps extends React.HTMLAttributes<HTMLDivElement> {
  audioSrc: string;
  title: string;
  subtitle?: string;
  imgSrc?: string;
  imgAlt?: string;
  variant?: MediaPlayerVariant;
  autoPlay?: boolean;
  preload?: 'metadata' | 'auto' | 'none';
  loop?: boolean;
  startTime?: number;
  showVolume?: boolean;
  onCloseClick?: (event: React.MouseEvent<HTMLButtonElement>) => void;
}

const baseClasses = `
  flex flex-col items-start w-full h-19.5
  data-[variant=compact]:w-104.5 group
  data-[variant=mini]:size-10 data-[variant=mini]:rounded-full
`;
const seekClasses = `_seek flex items-center w-full -mb-1.5 pr-0.5`;
const rowClasses = `
  _row flex items-center w-full bg-color-background-subtle py-5
  group-data-[variant=mini]:h-10 group-data-[variant=mini]:rounded-full group-data-[variant=mini]:py-0
`;
const leadClasses = `_lead flex items-center gap-4 min-w-0 flex-1 pl-4`;
const artworkClasses = `_artwork relative shrink-0 size-10 overflow-clip`;
const labelsClasses = `_labels flex flex-col min-w-0 gap-0`;
const subtitleClasses = `_subtitle text-xs font-medium text-color-content-weak truncate`;
const titleRowClasses = `_titleRow flex items-baseline gap-2 min-w-0`;
const titleClasses = `_title text-base font-medium text-color-content-default truncate`;
const timeDisplayClasses = `_timeDisplay text-xs font-medium text-color-content-weak whitespace-nowrap pl-2 border-l border-color-background-subtle`;
const controlsClasses = `_controls flex items-center gap-2`;
const volumeGroupClasses = `_volumeGroup text-comp-button-color-content-default justify-end flex items-center gap-2 pr-4`;
const volumeRangeClasses = `_volumeRange w-30`;
const actionsClasses = `_actions flex items-center gap-2`;

const seekStep = 0.1;

export const MediaPlayer = React.forwardRef<HTMLDivElement, MediaPlayerProps>(
  (
    {
      audioSrc,
      title,
      subtitle,
      imgSrc,
      imgAlt,
      variant = 'default',
      autoPlay = false,
      preload = 'metadata',
      loop = false,
      startTime = 0,
      showVolume = true,
      onCloseClick,
      className,
      ...rest
    },
    ref
  ) => {
    const audioRef = React.useRef<HTMLAudioElement>(null);
    const [duration, setDuration] = React.useState(0);
    const [currentTime, setCurrentTime] = React.useState(0);
    const [isScrubbing, setIsScrubbing] = React.useState(false);
    const [scrubTime, setScrubTime] = React.useState<number | null>(null);
    const [volume, setVolume] = React.useState(100);
    const [muted, setMuted] = React.useState(false);
    const [prevVolumeBeforeMute, setPrevVolumeBeforeMute] = React.useState<number | null>(null);

    const displayedCurrentTime = isScrubbing && scrubTime !== null ? scrubTime : currentTime;
    const normalizedDuration = Number.isFinite(duration) && duration > 0 ? duration : 0;
    const seekMax = normalizedDuration > 0 ? normalizedDuration : Math.max(displayedCurrentTime, 0);
    const seekValue = seekMax > 0 ? clamp(displayedCurrentTime, 0, seekMax) : 0;
    const timeDisplayLabel = `${formatTime(seekValue)} / ${formatTime(normalizedDuration)}`;

    const baseClassName = collapseWhitespace(composeClasses(baseClasses, className));
    const seekClassName = collapseWhitespace(composeClasses(seekClasses));
    const rowClassName = collapseWhitespace(composeClasses(rowClasses));
    const leadClassName = collapseWhitespace(composeClasses(leadClasses));
    const artworkClassName = collapseWhitespace(composeClasses(artworkClasses));
    const labelsClassName = collapseWhitespace(composeClasses(labelsClasses));
    const subtitleClassName = collapseWhitespace(composeClasses(subtitleClasses));
    const titleRowClassName = collapseWhitespace(composeClasses(titleRowClasses));
    const titleClassName = collapseWhitespace(composeClasses(titleClasses));
    const timeDisplayClassName = collapseWhitespace(composeClasses(timeDisplayClasses));
    const controlsClassName = collapseWhitespace(composeClasses(controlsClasses));
    const volumeGroupClassName = collapseWhitespace(composeClasses(volumeGroupClasses));
    const volumeRangeClassName = collapseWhitespace(composeClasses(volumeRangeClasses));
    const actionsClassName = collapseWhitespace(composeClasses(actionsClasses));

    React.useEffect(() => {
      setDuration(0);
      setCurrentTime(0);
      setIsScrubbing(false);
      setScrubTime(null);
    }, [audioSrc]);

    React.useEffect(() => {
      const audio = audioRef.current;
      if (!audio) return;

      const handleLoadedMetadata = () => {
        const audioDuration =
          Number.isFinite(audio.duration) && audio.duration > 0 ? audio.duration : 0;
        setDuration(audioDuration);
        const safeStartTime =
          startTime > 0 ? clamp(startTime, 0, audioDuration > 0 ? audioDuration : startTime) : 0;
        if (safeStartTime > 0) {
          try {
            audio.currentTime = safeStartTime;
          } catch {
            // no-op if the browser rejects the seek
          }
          setCurrentTime(safeStartTime);
        } else {
          setCurrentTime(Number.isFinite(audio.currentTime) ? audio.currentTime : 0);
        }
      };

      const handleTimeUpdate = () => {
        setCurrentTime(Number.isFinite(audio.currentTime) ? audio.currentTime : 0);
      };

      const handleDurationChange = () => {
        const audioDuration =
          Number.isFinite(audio.duration) && audio.duration > 0 ? audio.duration : 0;
        setDuration(audioDuration);
      };

      const handleVolumeChange = () => {
        setVolume(Math.round(clamp(audio.volume * 100, 0, 100)));
      };

      audio.addEventListener('loadedmetadata', handleLoadedMetadata);
      audio.addEventListener('timeupdate', handleTimeUpdate);
      audio.addEventListener('durationchange', handleDurationChange);
      audio.addEventListener('volumechange', handleVolumeChange);

      return () => {
        audio.removeEventListener('loadedmetadata', handleLoadedMetadata);
        audio.removeEventListener('timeupdate', handleTimeUpdate);
        audio.removeEventListener('durationchange', handleDurationChange);
        audio.removeEventListener('volumechange', handleVolumeChange);
      };
    }, [audioSrc, startTime]);

    const handleSeekChange = React.useCallback((nextValue: number) => {
      setIsScrubbing(true);
      setScrubTime(nextValue);
    }, []);

    const handleSeekCommit = React.useCallback((nextValue: number) => {
      const audio = audioRef.current;
      if (audio) {
        try {
          audio.currentTime = clamp(nextValue, 0, audio.duration || nextValue);
        } catch {
          // no-op if seeking fails
        }
      }
      setCurrentTime(nextValue);
      setScrubTime(null);
      setIsScrubbing(false);
    }, []);

    const handleVolumeChange = React.useCallback((nextValue: number) => {
      const bounded = clamp(nextValue, 0, 100);
      setVolume(bounded);
      setMuted(bounded === 0);
      const audio = audioRef.current;
      if (audio) {
        audio.volume = bounded / 100;
      }
    }, []);

    const handleToggleMute = React.useCallback(() => {
      if (muted) {
        const restore = prevVolumeBeforeMute ?? 100;
        setMuted(false);
        handleVolumeChange(restore);
      } else {
        setPrevVolumeBeforeMute(volume);
        setMuted(true);
        handleVolumeChange(0);
      }
    }, [muted, prevVolumeBeforeMute, volume, handleVolumeChange]);

    const skipBy = React.useCallback((deltaSeconds: number) => {
      const audio = audioRef.current;
      if (!audio) return;
      const dur = Number.isFinite(audio.duration) && audio.duration > 0 ? audio.duration : 0;
      const current = Number.isFinite(audio.currentTime) ? audio.currentTime : 0;
      const next = clamp(current + deltaSeconds, 0, dur > 0 ? dur : 0);
      try {
        audio.currentTime = next;
      } catch {
        // no-op if seeking fails
      }
      setCurrentTime(next);
    }, []);

    const handleReplay10 = React.useCallback(() => {
      skipBy(-10);
    }, [skipBy]);

    const handleForward10 = React.useCallback(() => {
      skipBy(10);
    }, [skipBy]);

    const handleControlPlay = React.useCallback(() => {
      const audio = audioRef.current;
      if (!audio) return;
      const playPromise = audio.play();
      playPromise?.catch(() => {});
    }, []);

    const handleControlPause = React.useCallback(() => {
      const audio = audioRef.current;
      audio?.pause();
    }, []);

    React.useEffect(() => {
      const audio = audioRef.current;
      if (!audio) return;
      audio.volume = volume / 100;
    }, [volume]);

    React.useEffect(() => {
      if (!showVolume) {
        setMuted(false);
        setPrevVolumeBeforeMute(null);
        setVolume(100); // [volume] effect will set audio.volume = 1
      }
    }, [showVolume]);

    const trimmedTitle = title.trim();
    const trimmedSubtitle = subtitle?.trim() ?? '';

    return (
      <div
        ref={ref}
        className={baseClassName}
        data-variant={variant}
        role="region"
        aria-label={trimmedTitle || 'Media player'}
        {...rest}
      >
        {variant !== 'mini' && (
          <div className={seekClassName} data-slot="_seek">
            <Slider
              value={seekValue}
              min={0}
              max={seekMax > 0 ? seekMax : 0}
              step={seekStep}
              onChange={handleSeekChange}
              onCommit={handleSeekCommit}
              ariaLabel="Seek"
            />
          </div>
        )}
        <div className={rowClassName} data-slot="_row">
          {variant === 'compact' ? (
            <>
              <div className={leadClassName} data-slot="_lead">
                <div className={controlsClassName} data-slot="_controls">
                  <MediaControl
                    data-slot="_playPause"
                    variant="dark"
                    size="lg"
                    defaultState={autoPlay ? 'playing' : 'paused'}
                    onPlay={handleControlPlay}
                    onPause={handleControlPause}
                  />
                </div>
                <div className={labelsClassName} data-slot="_labels">
                  <div className={subtitleClassName} data-slot="_subtitle">
                    {trimmedSubtitle}
                  </div>
                  <div className={titleRowClassName} data-slot="_titleRow">
                    <div className={titleClassName} data-slot="_title">
                      {trimmedTitle}
                    </div>
                  </div>
                </div>
              </div>

              <div className="flex items-center justify-end gap-8 flex-1 min-w-0">
                <IconButton
                  variant="bare"
                  icon={<CloseIcon />}
                  ariaLabel="Close"
                  onClick={onCloseClick}
                />
                <div className={actionsClassName} data-slot="_actions" />
              </div>
            </>
          ) : (
            <>
              {variant !== 'mini' && (
                <div className={leadClassName} data-slot="_lead">
                  {variant === 'default' &&
                    (imgSrc ? (
                      <div className={artworkClassName} data-slot="_artwork">
                        <img
                          className="block w-full h-full object-cover"
                          src={imgSrc}
                          alt={imgAlt ?? ''}
                        />
                      </div>
                    ) : (
                      <div className={artworkClassName} data-slot="_artwork" aria-hidden="true" />
                    ))}
                  <div className={labelsClassName} data-slot="_labels">
                    <div className={subtitleClassName} data-slot="_subtitle">
                      {trimmedSubtitle}
                    </div>
                    <div className={titleRowClassName} data-slot="_titleRow">
                      <div className={titleClassName} data-slot="_title">
                        {trimmedTitle}
                      </div>
                      <div
                        className={timeDisplayClassName}
                        data-slot="_timeDisplay"
                        aria-live="off"
                      >
                        {timeDisplayLabel}
                      </div>
                    </div>
                  </div>
                </div>
              )}

              <div className={controlsClassName} data-slot="_controls">
                {variant === 'default' && (
                  <IconButton
                    variant="bare"
                    icon={<Replay10Icon />}
                    ariaLabel="Replay 10 seconds"
                    onClick={handleReplay10}
                  />
                )}
                <MediaControl
                  data-slot="_playPause"
                  variant="dark"
                  size="lg"
                  defaultState={autoPlay ? 'playing' : 'paused'}
                  onPlay={handleControlPlay}
                  onPause={handleControlPause}
                />
                {variant === 'default' && (
                  <IconButton
                    variant="bare"
                    icon={<Forward10Icon />}
                    ariaLabel="Forward 10 seconds"
                    onClick={handleForward10}
                  />
                )}
              </div>

              <div className="flex items-center justify-end gap-8 flex-1 min-w-0">
                {variant === 'default' && (
                  <>
                    {showVolume && (
                      <div className={volumeGroupClassName} data-slot="_volumeGroup">
                        <div className={volumeRangeClassName} data-slot="_volumeRange">
                          <Slider
                            value={volume}
                            min={0}
                            max={100}
                            step={1}
                            onChange={handleVolumeChange}
                            ariaLabel="Volume"
                          />
                        </div>
                        <IconButton
                          variant="bare"
                          icon={
                            muted ? (
                              <VolumeOffIcon />
                            ) : volume > 50 ? (
                              <VolumeUpIcon />
                            ) : (
                              <VolumeDownIcon />
                            )
                          }
                          ariaLabel={muted ? 'Unmute' : 'Mute'}
                          onClick={handleToggleMute}
                        />
                      </div>
                    )}
                    <IconButton
                      variant="bare"
                      icon={<CloseIcon />}
                      ariaLabel="Close"
                      onClick={onCloseClick}
                    />
                  </>
                )}
                {variant !== 'mini' && <div className={actionsClassName} data-slot="_actions" />}
              </div>
            </>
          )}
        </div>
        <audio
          ref={audioRef}
          src={audioSrc}
          preload={preload}
          loop={loop}
          autoPlay={autoPlay}
          aria-hidden="true"
          tabIndex={-1}
        />
      </div>
    );
  }
);

MediaPlayer.displayName = 'MediaPlayer';
